    async def fetch_markets(self, params={}) -> List[Market]:
        """
        retrieves data on all markets for zebpayfutures

        https://github.com/zebpay/zebpay-api-references/blob/main/futures/api-reference/public-endpoints/market.md#get-market-info

        :param dict [params]: extra parameters specific to the exchange api endpoint
        :returns dict[]: an array of objects representing market data
        """
        response = await self.publicGetMarketMarkets(params)
        #
        #    {
        #        "data": {
        #            "symbol": "ETHUSDT",
        #            "status": "TRADING",
        #            "mainMarginPercent": "10",
        #            "baseAsset": "ETH",
        #            "quoteAsset": "USDT",
        #            "pricePrecision": 1,
        #            "quantityPrecision": 0.05,
        #            "baseAssetPrecision": 0,
        #            "quotePrecision": 0,
        #            "orderType": ["LIMIT", "MARKET"]
        #            "timeInForce": ["GTC"],
        #            "makerFee": "0.01",
        #            "takerFee": "0.01",
        #            "minLeverage": "1",
        #            "maxLeverage": "20"
        #        }
        #    }
        #
        result = []
        data = self.safe_value(response, 'data', {})
        markets = self.safe_value(data, 'symbols', [])
        for i in range(0, len(markets)):
            market = markets[i]
            id = self.safe_string(market, 'symbol')
            baseId = self.safe_string(market, 'baseAsset')
            quoteId = self.safe_string(market, 'quoteAsset')
            base = self.safe_currency_code(baseId)
            quote = self.safe_currency_code(quoteId)
            status = self.safe_string(market, 'status')
            result.append({
                'id': id,
                'symbol': market.symbol,
                'base': base,
                'quote': quote,
                'baseId': baseId,
                'quoteId': quoteId,
                'spot': False,
                'margin': False,
                'future': True,
                'option': False,
                'active': (status == 'Open'),
                'contract': True,
                'taker': self.safe_number(market, 'takerFee'),
                'maker': self.safe_number(market, 'makerFee'),
                'strike': None,
                'optionType': None,
                'precision': None,
                'limits': {
                    'leverage': {
                        'min': self.safe_number(market, 'minLeverage'),
                        'max': self.safe_number(market, 'maxLeverage'),
                    },
                },
                'info': market,
            })
        return result

