    async def add_margin(self, symbol: str, amount: float, params={}) -> MarginModification:
        """
        add margin

        https://github.com/zebpay/zebpay-api-references/blob/main/futures/api-reference/private-endpoints/trade.md#-add-margin-to-position

        :param str symbol: unified market symbol
        :param float amount: amount of margin to add
        :param dict [params]: extra parameters specific to the exchange API endpoint.
        :param str [params.positionId]: PositionId of the order to add margin.
        :param str [params.timestamp]: Tiemstamp.
        :returns dict: a `margin structure <https://docs.ccxt.com/#/?id=add-margin-structure>`
        """
        await self.load_markets()
        market = self.market(symbol)
        positionId = self.safe_string(params, 'positionId')
        timestamp = self.safe_integer(params, 'timestamp')
        if positionId is None:
            raise ArgumentsRequired(self.id + ' addMargin() requires a positionId parameter argument')
        params = self.omit(params, ['positionId', 'timestamp'])
        request: dict = {
            'symbol': market['id'],
            'amount': amount,
            'positionId': positionId,
            'timestamp': timestamp,
        }
        response = await self.privatePostTradeAddMargin(self.extend(request, params))
        #
        #    {
        #        "code": "200000",
        #        "data": {
        #            "symbol": "BTCINR",
        #            "type": "add",
        #            "amount": 1000,
        #            "code": "INR",
